INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Organisation comptable et gestion des entreprises', 'Formation sur les fondamentaux de la comptabilité et gestion financière.', 5, 250000.00, 'entreprise', '2026-05-05', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Meilleure organisation financière\n• Réduction des erreurs et pertes\n• Visibilité accrue sur la rentabilité\n• Aide à la prise de décisions stratégiques\n• Amélioration du contrôle budgétaire\n• Professionnalisation de la gestion comptable\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre les principes fondamentaux de la comptabilité, mettre en place une organisation comptable fiable, assurer un suivi financier rigoureux, analyser les données comptables pour la prise de décision, optimiser la gestion budgétaire et identifier les risques financiers.\n\n--- PRÉREQUIS ---\nConnaissances de base en gestion ou finance. Une expérience préalable en comptabilité est un atout mais non obligatoire.\n\n--- CONTENU ---\nMODULE 1 : Fondamentaux de la Comptabilité\nMODULE 2 : Organisation Comptable de l’Entreprise\nMODULE 3 : Gestion Financière et Budgétaire\nMODULE 4 : Lecture et Analyse des États Financiers\nMODULE 5 : Risques Comptables et Bonnes Pratiques\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nComptables, gestionnaires, responsables financiers, chefs d’entreprise, étudiants en gestion et toute personne impliquée dans la gestion comptable et financière.\n\n--- MÉTHODES ---\nApproche pratique et orientée terrain, études de cas réels, exercices et simulations, échanges d’expériences, supports et modèles fournis.\n\n--- SUPPORTS ---\nDocuments comptables types, logiciels de gestion comptable, tableurs Excel, études de cas, supports PDF et modèles pratiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
